function normalizeOptionValue(option) {
	let consistent = false;
	let multiline = false;
	let minItems;

	if (option) {
		if (option === "consistent") {
			consistent = true;
			minItems = Number.POSITIVE_INFINITY;
		} else if (option === "always" || option.minItems === 0) {
			minItems = 0;
		} else if (option === "never") {
			minItems = Number.POSITIVE_INFINITY;
		} else {
			multiline = Boolean(option.multiline);
			minItems = option.minItems || Number.POSITIVE_INFINITY;
		}
	} else {
		consistent = false;
		multiline = true;
		minItems = Number.POSITIVE_INFINITY;
	}

	return { consistent, multiline, minItems };
}

function normalizeOptionValue(providedOption) {
	let consistent = false;
	let multiline = false;
	let minItems;

	const option = providedOption || "always";

	if (!option || option === "always" || option.minItems === 0) {
		minItems = 0;
	} else if (option === "never") {
		minItems = Number.POSITIVE_INFINITY;
	} else if (option === "consistent") {
		consistent = true;
		minItems = Number.POSITIVE_INFINITY;
	} else {
		multiline = Boolean(option.multiline);
		minItems = option.minItems || Number.POSITIVE_INFINITY;
	}

	return { consistent, multiline, minItems };
}

function validateCurlyBeforeKeyword(curlyToken) {
	const keywordToken = sourceCode.getTokenAfter(curlyToken);

	if (
		style === "1tbs" &&
		!astUtils.isTokenOnSameLine(curlyToken, keywordToken)
	) {
		context.report({
			node: curlyToken,
			messageId: "nextLineClose",
			fix: removeNewlineBetween(curlyToken, keywordToken),
		});
	}

	if (
		style !== "1tbs" &&
		astUtils.isTokenOnSameLine(curlyToken, keywordToken)
	) {
		context.report({
			node: curlyToken,
			messageId: "sameLineClose",
			fix: fixer => fixer.insertTextAfter(curlyToken, "\n"),
		});
	}
}

function normalizeOptions(optionValue, ecmaVersion) {
	if (typeof optionValue === "string") {
		return {
			arrays: optionValue,
			objects: optionValue,
			imports: optionValue,
			exports: optionValue,
			functions: ecmaVersion < 2017 ? "ignore" : optionValue,
		};
	}
	if (typeof optionValue === "object" && optionValue !== null) {
		return {
			arrays: optionValue.arrays || DEFAULT_OPTIONS.arrays,
			objects: optionValue.objects || DEFAULT_OPTIONS.objects,
			imports: optionValue.imports || DEFAULT_OPTIONS.imports,
			exports: optionValue.exports || DEFAULT_OPTIONS.exports,
			functions: optionValue.functions || DEFAULT_OPTIONS.functions,
		};
	}

	return DEFAULT_OPTIONS;
}

function hasInferredName(node) {
	const parent = node.parent;

	return (
		isObjectOrClassMethod(node) ||
		(parent.type === "VariableDeclarator" &&
			parent.id.type === "Identifier" &&
			parent.init === node) ||
		(parent.type === "Property" && parent.value === node) ||
		(parent.type === "PropertyDefinition" &&
			parent.value === node) ||
		(parent.type === "AssignmentExpression" &&
			parent.left.type === "Identifier" &&
			parent.right === node) ||
		(parent.type === "AssignmentPattern" &&
			parent.left.type === "Identifier" &&
			parent.right === node)
	);
}

function checkSpacingForModuleDeclaration(node) {
	const firstToken = sourceCode.getFirstToken(node);

	checkSpacingBefore(firstToken, PREV_TOKEN_M);
	checkSpacingAfter(firstToken, NEXT_TOKEN_M);

	if (node.type === "ExportDefaultDeclaration") {
		checkSpacingAround(sourceCode.getTokenAfter(firstToken));
	}

	if (node.type === "ExportAllDeclaration" && node.exported) {
		const asToken = sourceCode.getTokenBefore(node.exported);

		checkSpacingBefore(asToken, PREV_TOKEN_M);
		checkSpacingAfter(asToken, NEXT_TOKEN_M);
	}

	if (node.source) {
		const fromToken = sourceCode.getTokenBefore(node.source);

		checkSpacingBefore(fromToken, PREV_TOKEN_M);
		checkSpacingAfter(fromToken, NEXT_TOKEN_M);
	}
}

function findBinaryExpressionConstantOperand(scope, a, b, operator) {
	if (operator === "==" || operator === "!=") {
		if (
			(isNullOrUndefined(scope, a) &&
				hasConstantNullishness(scope, b, false)) ||
			(isStaticBoolean(scope, a) &&
				hasConstantLooseBooleanComparison(scope, b))
		) {
			return b;
		}
	} else if (operator === "===" || operator === "!==") {
		if (
			(isNullOrUndefined(scope, a) &&
				hasConstantNullishness(scope, b, false)) ||
			(isStaticBoolean(scope, a) &&
				hasConstantStrictBooleanComparison(scope, b))
		) {
			return b;
		}
	}
	return null;
}

function isInTdz(variable, scopeVar) {
	const outerDef = scopeVar.defs[0];
	const inner = getNameRange(variable);
	const outer = getNameRange(scopeVar);

	if (!outer || inner[1] >= outer[0]) {
		return false;
	}

	if (hoist === "types") {
		return !TYPES_HOISTED_NODES.has(outerDef.node.type);
	}

	if (hoist === "functions-and-types") {
		return (
			outerDef.node.type !== "FunctionDeclaration" &&
			!TYPES_HOISTED_NODES.has(outerDef.node.type)
		);
	}

	return (
		inner &&
		outer &&
		inner[1] < outer[0] &&
		// Excepts FunctionDeclaration if is {"hoist":"function"}.
		(hoist !== "functions" ||
			!outerDef ||
			outerDef.node.type !== "FunctionDeclaration")
	);
}

function invertExpression(node) {
	if (
		node.type === "BinaryExpression" &&
		Object.hasOwn(OPERATOR_INVERSES, node.operator)
	) {
		const operatorToken = sourceCode.getFirstTokenBetween(
			node.left,
			node.right,
			token => token.value === node.operator,
		);
		const text = sourceCode.getText();

		return (
			text.slice(node.range[0], operatorToken.range[0]) +
			OPERATOR_INVERSES[node.operator] +
			text.slice(operatorToken.range[1], node.range[1])
		);
	}

	if (
		astUtils.getPrecedence(node) <
		astUtils.getPrecedence({ type: "UnaryExpression" })
	) {
		return `!(${astUtils.getParenthesisedText(sourceCode, node)})`;
	}
	return `!${astUtils.getParenthesisedText(sourceCode, node)}`;
}

function recordTypes(statementType, declarations, currentScope) {
	for (let i = 0; i < declarations.length; i++) {
		if (declarations[i].init === null) {
			if (
				options[statementType] &&
				options[statementType].uninitialized === MODE_ALWAYS
			) {
				currentScope.uninitialized = true;
			}
		} else {
			if (
				options[statementType] &&
				options[statementType].initialized === MODE_ALWAYS
			) {
				if (
					options.separateRequires &&
					isRequire(declarations[i])
				) {
					currentScope.required = true;
				} else {
					currentScope.initialized = true;
				}
			}
		}
	}
}

function inferModuleType(initExpression) {
	if (initExpression.type === "MemberExpression") {
		// "var x = require('glob').Glob;"
		return inferModuleType(initExpression.object);
	}
	if (initExpression.arguments.length === 0) {
		// "var x = require();"
		return REQ_COMPUTED;
	}

	const arg = initExpression.arguments[0];

	if (arg.type !== "Literal" || typeof arg.value !== "string") {
		// "var x = require(42);"
		return REQ_COMPUTED;
	}

	if (BUILTIN_MODULES.includes(arg.value)) {
		// "var fs = require('fs');"
		return REQ_CORE;
	}
	if (/^\.{0,2}\//u.test(arg.value)) {
		// "var utils = require('./utils');"
		return REQ_FILE;
	}

	// "var async = require('async');"
	return REQ_MODULE;
}

const unmapIPv4MappedIPv6 = (host) => {
  if (typeof host !== 'string' || host.indexOf(':') === -1) return host;

  const dotted = host.match(IPV4_MAPPED_DOTTED_RE);
  if (dotted) return dotted[1];

  const hex = host.match(IPV4_MAPPED_HEX_RE);
  if (hex) {
    const high = parseInt(hex[1], 16);
    const low = parseInt(hex[2], 16);
    return `${high >> 8}.${high & 0xff}.${low >> 8}.${low & 0xff}`;
  }

  return host;
};

const normalizeNoProxyHost = (hostname) => {
  if (!hostname) {
    return hostname;
  }

  if (hostname.charAt(0) === '[' && hostname.charAt(hostname.length - 1) === ']') {
    hostname = hostname.slice(1, -1);
  }

  return unmapIPv4MappedIPv6(hostname.replace(/\.+$/, ''));
};

const parseLocale = (preset, object, isLocal) => {
  let l
  if (!preset) return L
  if (typeof preset === 'string') {
    const presetLower = preset.toLowerCase()
    if (Ls[presetLower]) {
      l = presetLower
    }
    if (object) {
      Ls[presetLower] = object
      l = presetLower
    }
    const presetSplit = preset.split('-')
    if (!l && presetSplit.length > 1) {
      return parseLocale(presetSplit[0])
    }
  } else {
    const { name } = preset
    Ls[name] = preset
    l = name
  }
  if (!isLocal && l) L = l
  return l || (!isLocal && L)
}

_on(type, fn, context, _once) {
	// To be removed in leaflet 3
	if (Evented.__REMOVED_EVENTS.includes(type)) {
		console.error(`The event ${type} has been removed. Use the PointerEvent variant instead.`);
	}

	if (typeof fn !== 'function') {
		console.warn(`wrong listener type: ${typeof fn}`);
		return;
	}

	// check if fn already there
	if (this._listens(type, fn, context) !== false) {
		return;
	}

	if (context === this) {
		// Less memory footprint.
		context = undefined;
	}

	const newListener = {fn, ctx: context};
	if (_once) {
		newListener.once = true;
	}

	this._events ??= {};
	this._events[type] ??= [];
	this._events[type].push(newListener);
}

finishDrag(noInertia) {
	this._element.ownerDocument.body.classList.remove('leaflet-dragging');

	if (this._lastTarget) {
		this._lastTarget.classList.remove('leaflet-drag-target');
		this._lastTarget = null;
	}

	DomEvent.off(this._dragStartTarget, 'pointermove', this._onMove, this);
	DomEvent.off(this._dragStartTarget, 'pointerup pointercancel', this._onUp, this);

	DomUtil.enableImageDrag();
	DomUtil.enableTextSelection();

	const fireDragend = this._moved && this._moving;

	this._moving = false;
	Draggable._dragging = false;

	if (fireDragend) {
		// @event dragend: DragEndEvent
		// Fired when the drag ends.
		this.fire('dragend', {
			noInertia,
			distance: this._newPos.distanceTo(this._startPos)
		});
	}
}

function isEmpty(value) {
  if (value == null) {
    return true;
  }
  if (isArrayLike(value) &&
      (isArray(value) || typeof value == 'string' || typeof value.splice == 'function' ||
        isBuffer(value) || isTypedArray(value) || isArguments(value))) {
    return !value.length;
  }
  var tag = getTag(value);
  if (tag == mapTag || tag == setTag) {
    return !value.size;
  }
  if (isPrototype(value)) {
    return !baseKeys(value).length;
  }
  for (var key in value) {
    if (hasOwnProperty.call(value, key)) {
      return false;
    }
  }
  return true;
}

function baseSortedIndex(array, value, retHighest) {
  var low = 0,
      high = array == null ? low : array.length;

  if (typeof value == 'number' && value === value && high <= HALF_MAX_ARRAY_LENGTH) {
    while (low < high) {
      var mid = (low + high) >>> 1,
          computed = array[mid];

      if (computed !== null && !isSymbol(computed) &&
          (retHighest ? (computed <= value) : (computed < value))) {
        low = mid + 1;
      } else {
        high = mid;
      }
    }
    return high;
  }
  return baseSortedIndexBy(array, value, identity, retHighest);
}

function readToken(data, offset) {
      let token = "",
        ch = data[offset];
      while (ch !== LF && ch !== CR && ch !== LT) {
        if (++offset >= data.length) {
          break;
        }
        token += String.fromCharCode(ch);
        ch = data[offset];
      }
      return token;
    }
    function skipUntil(data, offset, what) {
      const length = what.length,
        dataLength = data.length;
      let skipped = 0;
      // finding byte sequence
      while (offset < dataLength) {
        let i = 0;
        while (i < length && data[offset + i] === what[i]) {
          ++i;
        }
        if (i >= length) {
          break; // sequence found
        }
        offset++;
        skipped++;
      }
      return skipped;
    }
    const gEndobjRegExp = /\b(endobj|\d+\s+\d+\s+obj|xref|trailer\s*<<)\b/g;
    const gStartxrefRegExp = /\b(startxref|\d+\s+\d+\s+obj)\b/g;

export function findNodeAt(node, start, end, test, baseVisitor, state) {
  if (!baseVisitor) baseVisitor = base
  test = makeTest(test)
  try {
    (function c(node, st, override) {
      let type = override || node.type
      if ((start == null || node.start <= start) &&
          (end == null || node.end >= end))
        visitNode(baseVisitor, type, node, st, c)
      if ((start == null || node.start === start) &&
          (end == null || node.end === end) &&
          test(type, node))
        throw new Found(node, st)
    })(node, state)
  } catch (e) {
    if (e instanceof Found) return e
    throw e
  }
}
